// Read from pre-insert node to get supply data (Insert output drops non-mapped fields)
const item = $('Reject If Already Approved').first().json;
const supplies = item.supplies || [];
if (!Array.isArray(supplies) || supplies.length === 0) return [];
return supplies.map(s => ({ json: {
